  ('social-worker-moex-01751', 'social-worker', 'social-worker-moex-108-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '有關社會工作師法的立法目的，下列敘述何者錯誤？', '["建立社會工作專業服務體系", "提升社會工作師的專業地位", "明定社會工作師的自我利益", "確保受服務對象之權益"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "ff75e56582d6", "answer_pdf_sha1": "cf487df9a01b", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01752', 'social-worker', 'social-worker-moex-108-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '有關社會救助法中醫療補助之規定，下列何者錯誤？', '["申請對象僅限於低收入戶傷病患者", "參加全民健康保險可取得之醫療給付者，不得再申請醫療補助", "低收入戶參加全民健康保險之保險費，由中央主管機關編列預算補助", "其他法令性質相同之醫療補助，不得重複補助"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "ff75e56582d6", "answer_pdf_sha1": "cf487df9a01b", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01753', 'social-worker', 'social-worker-moex-108-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依據特殊境遇家庭扶助條例第8條之規定，下列何者可領取教育補助？', '["就讀高中高職學雜費全免", "就讀社區大學減免學雜費60%", "就讀高中高職、大專院校減免學雜費60%", "就讀大專院校學雜費全免"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "ff75e56582d6", "answer_pdf_sha1": "cf487df9a01b", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01754', 'social-worker', 'social-worker-moex-108-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依據性別工作平等法，對於促進性別工作平等措施，下列敘述何者錯誤？', '["女性受僱者因生理日致工作有困難者，每月得請生理假1日，全年請假日數未逾3日，不併入 病假計算，其餘日數併入病假計算", "受僱者於其配偶分娩時，雇主應給予陪產假3日", "受僱於僱用30人以上雇主之受僱者，為撫養未滿3歲子女，得向雇主請求每天減少工作時間 1小時或調整工作時間", "受僱者於其家庭成員預防接種、發生嚴重之疾病或其他重大事故須親自照顧時，得請家庭照顧 假，其請假日數併入事假計算，全年以7日為限"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "ff75e56582d6", "answer_pdf_sha1": "cf487df9a01b", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01755', 'social-worker', 'social-worker-moex-108-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依據志願服務法規定，關於志願服務榮譽卡的核發與使用，下列敘述何者正確？', '["志工服務年資滿3年，服務時數達300小時以上者始得申請", "由志願服務運用單位核發", "憑志願服務榮譽卡得享公民營風景區及文教設施門票免費", "民防、義勇警察、義勇交通警察等人員不適用志願服務榮譽卡"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "ff75e56582d6", "answer_pdf_sha1": "cf487df9a01b", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01756', 'social-worker', 'social-worker-moex-108-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '國民年金法第17條規定，可以補繳保險費的最高期限為多少年？', '["3年", "5年", "10年", "15年"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "ff75e56582d6", "answer_pdf_sha1": "cf487df9a01b", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01757', 'social-worker', 'social-worker-moex-108-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依長期照顧服務法第3條「長期照顧」之定義，下列敘述何者正確？', '["指身心失能持續已達3個月以上者；而身心失能者是指身體或心智功能完全喪失，致其日常生 活需完全依賴他人協助者", "指身心失能持續或預期達5個月以上者；而身心失能者是指身心功能必須完全喪失，致其日常 生活需完全依賴他人協助者", "指身心失能持續已達或預期達6個月以上者；而身心失能者是指身體或心智功能部分或全部喪 失，致其日常生活需他人協助者", "指身心失能持續已達或預期須達1年以上者；而身心失能者是指身心功能完全喪失，致其日常 生活需完全依賴他人協助者"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "ff75e56582d6", "answer_pdf_sha1": "cf487df9a01b", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01758', 'social-worker', 'social-worker-moex-108-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '有關兒童及少年未來教育與發展帳戶條例第6條所示其適用對象，下列何者錯誤？', '["具社會救助法所定之低收入戶或中低收入戶資格，且於中華民國105年1月1日以後出生者", "具社會救助法所定之低收入戶或中低收入戶資格，且未滿18歲者", "依據兒童及少年福利與權益保障法相關規定安置2年以上，由法院指定直轄市、縣（市）主管 機關、兒童及少年福利機構負責人為監護人者", "其他經中央主管機關公告指定者"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "ff75e56582d6", "answer_pdf_sha1": "cf487df9a01b", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01759', 'social-worker', 'social-worker-moex-108-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依據兒童及少年未來教育與發展帳戶條例，其第16條的條文內容，下列何者錯誤？', '["直轄市、縣（市）主管機關應於開戶人滿18歲3個月前，通知其檢具儲金用途相關證明辦理 帳戶款項之請領並結清帳戶", "儲金用途以助於開戶人就學、就業、職業訓練或創業為限", "開戶人於滿18歲之日起10年內，因死亡而未依規定辦理帳戶款項之請領及結清帳戶者，得由 原為其開戶之法定代理人或最近親屬任一人申請提領該帳戶之自存款及其利息並結清帳戶", "開戶人滿18歲之日起10年內，權利人未依規定申請提領及結清帳戶者，開戶人兒少教育發展 帳戶所餘款項，歸屬國庫"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "ff75e56582d6", "answer_pdf_sha1": "cf487df9a01b", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01760', 'social-worker', 'social-worker-moex-108-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '針對近些年國內連續發生蓄意傷人或隨機殺人的事件，尤其是以幼童為對象造成社會的恐慌與不 安，政府對此特於民國107年提出強化社會安全網計畫，其強調用新思維及整合策略來進行，下 列敘述何者錯誤？', '["本計畫強調社會安全網介入的焦點由「個人為中心」轉變成「以家庭為中心」", "建構以家庭為中心，以社區為基礎的服務模式", "協助一般家庭建構以社區為基礎的支持體系與提供支持性服務", "以預防為優先，及早辨識脆弱兒童與家庭"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "ff75e56582d6", "answer_pdf_sha1": "cf487df9a01b", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
